import{_ as e,o as i,c as o,a2 as s}from"./chunks/framework.DCVnL8g5.js";const h=JSON.parse('{"title":"Notebooks en Databricks","description":"","frontmatter":{},"headers":[],"relativePath":"data-engineering/databricks/02-notebooks.md","filePath":"data-engineering/databricks/02-notebooks.md","lastUpdated":1782521464000}'),n={name:"data-engineering/databricks/02-notebooks.md"};function t(l,a,r,c,d,u){return i(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="notebooks-en-databricks" tabindex="-1">Notebooks en Databricks <a class="header-anchor" href="#notebooks-en-databricks" aria-label="Permalink to &quot;Notebooks en Databricks&quot;">​</a></h1><p>Los notebooks de Databricks son herramientas interactivas que permiten combinar código, texto explicativo, visualizaciones y resultados en un único documento. Son fundamentales para el análisis de datos, el desarrollo de modelos y la colaboración en equipos.</p><hr><h2 id="¿que-son-los-notebooks-de-databricks" tabindex="-1">¿Qué son los Notebooks de Databricks? <a class="header-anchor" href="#¿que-son-los-notebooks-de-databricks" aria-label="Permalink to &quot;¿Qué son los Notebooks de Databricks?&quot;">​</a></h2><p>Un notebook es un entorno de trabajo que integra código ejecutable, texto en formato Markdown, gráficos y resultados en tiempo real. En Databricks, los notebooks están diseñados para facilitar la interacción con Spark y el análisis colaborativo de datos.</p><h3 id="caracteristicas-principales" tabindex="-1">Características principales: <a class="header-anchor" href="#caracteristicas-principales" aria-label="Permalink to &quot;Características principales:&quot;">​</a></h3><ul><li><strong>Multilenguaje:</strong> Permite escribir código en Python, Scala, SQL, R y Markdown.</li><li><strong>Colaboración en tiempo real:</strong> Varios usuarios pueden trabajar simultáneamente en un mismo notebook.</li><li><strong>Integración con Spark:</strong> Ejecución nativa de operaciones distribuidas.</li><li><strong>Soporte para visualizaciones:</strong> Gráficos personalizables para explorar los datos.</li></ul><hr><h2 id="creacion-y-gestion-de-notebooks" tabindex="-1">Creación y Gestión de Notebooks <a class="header-anchor" href="#creacion-y-gestion-de-notebooks" aria-label="Permalink to &quot;Creación y Gestión de Notebooks&quot;">​</a></h2><h3 id="creacion-de-un-notebook" tabindex="-1">Creación de un notebook <a class="header-anchor" href="#creacion-de-un-notebook" aria-label="Permalink to &quot;Creación de un notebook&quot;">​</a></h3><ol><li><p><strong>Accede a Databricks:</strong></p><ul><li>Inicia sesión en tu instancia de Databricks.</li><li>Dirígete a la sección &quot;Workspace&quot;.</li></ul></li><li><p><strong>Crea un nuevo notebook:</strong></p><ul><li>Haz clic en el botón &quot;Create&quot; y selecciona &quot;Notebook&quot;.</li><li>Asigna un nombre al notebook y elige el lenguaje principal (Python, SQL, etc.).</li><li>Selecciona un clúster activo para ejecutar el notebook.</li></ul></li><li><p><strong>Guarda el notebook:</strong></p><ul><li>Los notebooks se almacenan automáticamente en el espacio de trabajo.</li></ul></li></ol><h3 id="gestion-de-notebooks" tabindex="-1">Gestión de notebooks <a class="header-anchor" href="#gestion-de-notebooks" aria-label="Permalink to &quot;Gestión de notebooks&quot;">​</a></h3><ul><li><strong>Renombrar:</strong> Haz clic en el nombre del notebook en la parte superior y edítalo.</li><li><strong>Mover:</strong> Arrastra y suelta el notebook dentro de las carpetas del workspace.</li><li><strong>Compartir:</strong> Haz clic en &quot;Share&quot; para gestionar permisos de acceso.</li></ul><hr><h2 id="ejecucion-de-celdas" tabindex="-1">Ejecución de Celdas <a class="header-anchor" href="#ejecucion-de-celdas" aria-label="Permalink to &quot;Ejecución de Celdas&quot;">​</a></h2><h3 id="tipos-de-celdas" tabindex="-1">Tipos de celdas <a class="header-anchor" href="#tipos-de-celdas" aria-label="Permalink to &quot;Tipos de celdas&quot;">​</a></h3><ol><li><strong>Celdas de código:</strong> Ejecutan código en el lenguaje seleccionado.</li><li><strong>Celdas de texto:</strong> Permiten escribir explicaciones utilizando Markdown.</li></ol><h3 id="ejecutar-una-celda" tabindex="-1">Ejecutar una celda <a class="header-anchor" href="#ejecutar-una-celda" aria-label="Permalink to &quot;Ejecutar una celda&quot;">​</a></h3><ul><li>Usa el atajo <code>Shift + Enter</code> para ejecutar la celda actual y pasar a la siguiente.</li><li>Para ejecutar todas las celdas, selecciona &quot;Run All&quot; en el menú de ejecución.</li></ul><h3 id="ejemplo" tabindex="-1">Ejemplo: <a class="header-anchor" href="#ejemplo" aria-label="Permalink to &quot;Ejemplo:&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Código en Python</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">spark.range(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">5</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">).show()</span></span></code></pre></div><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># Título en Markdown</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Este es un ejemplo de celda de texto.</span></span></code></pre></div><hr><h2 id="visualizacion-de-resultados" tabindex="-1">Visualización de Resultados <a class="header-anchor" href="#visualizacion-de-resultados" aria-label="Permalink to &quot;Visualización de Resultados&quot;">​</a></h2><p>Los notebooks de Databricks incluyen herramientas para crear visualizaciones directamente desde los resultados.</p><h3 id="crear-una-visualizacion" tabindex="-1">Crear una visualización: <a class="header-anchor" href="#crear-una-visualizacion" aria-label="Permalink to &quot;Crear una visualización:&quot;">​</a></h3><ol><li><strong>Ejecuta una consulta:</strong> Por ejemplo, usando Spark SQL.</li><li><strong>Selecciona el icono de gráfico:</strong> Haz clic en &quot;+&quot; encima de los resultados.</li><li><strong>Configura el gráfico:</strong> Elige el tipo de visualización (barras, líneas, etc.) y personaliza los ejes.</li></ol><h3 id="ejemplo-1" tabindex="-1">Ejemplo: <a class="header-anchor" href="#ejemplo-1" aria-label="Permalink to &quot;Ejemplo:&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SELECT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> department, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">COUNT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">AS</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> total</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">FROM</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> employees</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">GROUP BY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> department</span></span></code></pre></div><p>Configura un gráfico de barras para mostrar el total por departamento.</p><hr><h2 id="atajos-y-mejores-practicas" tabindex="-1">Atajos y Mejores Prácticas <a class="header-anchor" href="#atajos-y-mejores-practicas" aria-label="Permalink to &quot;Atajos y Mejores Prácticas&quot;">​</a></h2><h3 id="atajos-utiles" tabindex="-1">Atajos útiles <a class="header-anchor" href="#atajos-utiles" aria-label="Permalink to &quot;Atajos útiles&quot;">​</a></h3><ul><li><code>Ctrl + /</code>: Comentar o descomentar una línea de código.</li><li><code>Ctrl + Enter</code>: Ejecutar la celda actual.</li><li><code>Shift + Tab</code>: Mostrar ayuda para una función o método.</li></ul><h3 id="mejores-practicas" tabindex="-1">Mejores prácticas <a class="header-anchor" href="#mejores-practicas" aria-label="Permalink to &quot;Mejores prácticas&quot;">​</a></h3><ol><li><strong>Organización:</strong> Divide el código en celdas pequeñas y lógicas.</li><li><strong>Documentación:</strong> Acompaña el código con explicaciones en Markdown.</li><li><strong>Reutilización:</strong> Guarda fragmentos comunes en &quot;Databricks Repos&quot; o como widgets reutilizables.</li></ol><hr><h2 id="integracion-con-pipelines" tabindex="-1">Integración con Pipelines <a class="header-anchor" href="#integracion-con-pipelines" aria-label="Permalink to &quot;Integración con Pipelines&quot;">​</a></h2><p>Los notebooks pueden integrarse en flujos de trabajo automatizados mediante herramientas como Databricks Workflows o Apache Airflow.</p><h3 id="ejemplo-de-integracion" tabindex="-1">Ejemplo de integración: <a class="header-anchor" href="#ejemplo-de-integracion" aria-label="Permalink to &quot;Ejemplo de integración:&quot;">​</a></h3><ul><li>Configura un pipeline en Databricks Workflows para ejecutar un notebook diariamente.</li><li>Usa parámetros para personalizar las ejecuciones.</li></ul><hr><h2 id="conclusion" tabindex="-1">Conclusión <a class="header-anchor" href="#conclusion" aria-label="Permalink to &quot;Conclusión&quot;">​</a></h2><p>Los notebooks en Databricks son una herramienta versátil y poderosa para trabajar con datos y Spark. Su capacidad de combinar código, visualizaciones y colaboración en tiempo real los convierte en una pieza clave para proyectos de ciencia de datos y análisis avanzado. Maximiza su uso organizando tu trabajo, documentando bien tu código y aprovechando sus capacidades de integración con flujos de trabajo.</p>`,44)])])}const k=e(n,[["render",t]]);export{h as __pageData,k as default};
